아래는 서버에서 조회한 상품 등록일을 Client Component에 전달하는 올바른 코드이다.
이 코드에서 `product.createdAt.toISOString()`을 사용하는 이유로 올바른 것은?
```tsx
// Server Component
export default async function ProductDetailPage({ params }) {
  const product = await prisma.product.findUnique({ where: { id: params.id } });

  return (
    <ProductActions createdAt={product.createdAt.toISOString()} />
  );
}

// Client Component
'use client';
export default function ProductActions({ createdAt }: { createdAt: string }) {
  return <div>등록일: {new Date(createdAt).toLocaleDateString()}</div>;
}
```

